// Microbenchmark comparing add/sub/mul generated by gen_ff.py (LLVM-IR) and
// gen_ff_x64.py (x64 asm) within a single executable.
//
// Both generators emit under distinct prefixes (llvm_ / x64_) so they coexist.
// llvm_var_mul is the -var-p variant: p/ip are read from a runtime array
// (llvm_var_param) instead of being baked in as immediates.
// llvm_argp_mul is the -arg-p variant: a pointer to struct { uint64_t ip;
// uint64_t p[N]; } is passed as the 4th argument. It reuses llvm_var_param,
// which has exactly that [ip, p[N]] layout, so it runs on identical data.
// Built and run via the `bench` target in the Makefile.
#include <cstdint>
#include <cstdio>
#include <cstring>
#include <cstdlib>
#include <chrono>
#include <initializer_list>
#include <vector>
#include <mcl_fp.h>
#include <mcl/fp_def.hpp>
#include <mcl/fp_tower.hpp>
#include <cybozu/xorshift.hpp>
#include <cybozu/option.hpp>
#include <set>

using namespace mcl;
using namespace mcl::fp;

typedef void (*FpOp)(uint64_t* z, const uint64_t* x, const uint64_t* y);
// add/sub/mul with the prime context passed as the 4th argument.
typedef void (*FpOp4)(uint64_t* z, const uint64_t* x, const uint64_t* y,
											const uint64_t* p);

extern "C" {
	const uint8_t* llvm_get_prime();
	void llvm_add(uint64_t*, const uint64_t*, const uint64_t*);
	void llvm2_add(uint64_t*, const uint64_t*, const uint64_t*);
	void llvm_sub(uint64_t*, const uint64_t*, const uint64_t*);
	void llvm2_sub(uint64_t*, const uint64_t*, const uint64_t*);
	void llvm_mul(uint64_t*, const uint64_t*, const uint64_t*);
	void llvm_var_add(uint64_t*, const uint64_t*, const uint64_t*);
	void llvm_var2_add(uint64_t*, const uint64_t*, const uint64_t*);
	void llvm_var_sub(uint64_t*, const uint64_t*, const uint64_t*);
	void llvm_var2_sub(uint64_t*, const uint64_t*, const uint64_t*);
	void llvm_var_mul(uint64_t*, const uint64_t*, const uint64_t*);
	void llvm_argp_add(uint64_t*, const uint64_t*, const uint64_t*, const uint64_t*);
	void llvm_argp2_add(uint64_t*, const uint64_t*, const uint64_t*, const uint64_t*);
	void llvm_argp_sub(uint64_t*, const uint64_t*, const uint64_t*, const uint64_t*);
	void llvm_argp2_sub(uint64_t*, const uint64_t*, const uint64_t*, const uint64_t*);
	void llvm_argp_mul(uint64_t*, const uint64_t*, const uint64_t*, const uint64_t*);
	// [ip, p[N]] array emitted by the -var-p generator; same layout as the
	// struct { uint64_t ip; uint64_t p[N]; } expected by llvm_argp_mul.
	extern const uint64_t llvm_var_param[];
	void x64_add(uint64_t*, const uint64_t*, const uint64_t*);
	void x642_add(uint64_t*, const uint64_t*, const uint64_t*);
	void x64_sub(uint64_t*, const uint64_t*, const uint64_t*);
	void x642_sub(uint64_t*, const uint64_t*, const uint64_t*);
	void x64_mul(uint64_t*, const uint64_t*, const uint64_t*);
	// mulx-only variant (no adcx/adox) for pre-Broadwell CPUs
	void x64_mul_wo_adx(uint64_t*, const uint64_t*, const uint64_t*);
}


template<class T>
void check(const char *name, void (*f)(T& x, const T& y, const T& z), FpOp4 f0, std::initializer_list<FpOp> fs)
{
	const size_t n = sizeof(T) / sizeof(Fp);
	cybozu::XorShift rg;
	T x, y, z, z0;
	const Unit *px = (const Unit*)&x;
	const Unit *py = (const Unit*)&y;
	for (int j = 0; j < 100; j++) {
		for (size_t i = 0; i < n; i++) {
			((Fp*)&x)[i].setByCSPRNG(rg);
			((Fp*)&y)[i].setByCSPRNG(rg);
		}
		f(z, x, y);
		f0((Unit*)&z0, px, py, llvm_var_param);
		if (z != z0) {
			fprintf(stderr, "ERR %s f0\n", name);
			exit(1);
		}
		int idx = 0;
		for (FpOp f1 : fs) {
			f1((Unit*)&z0, px, py);
			if (z != z0) {
				fprintf(stderr, "ERR %s f1[%d]\n", name, idx);
				exit(1);
			}
			idx++;
		}
	}
}

// Time one measurement. op(k) runs the operation on stream k. P streams:
// P=1 is a serial dependency chain (latency); P=4 runs independent chains
// (throughput). The chained operands stay below p, so they do not diverge.
template<class Op>
static double measure(Op op, int P, long loop)
{
	long m = loop / P;
	for (long i = 0; i < m / 10; i++) for (int k = 0; k < P; k++) op(k); // warmup
	auto t0 = std::chrono::steady_clock::now();
	for (long i = 0; i < m; i++) for (int k = 0; k < P; k++) op(k);
	auto t1 = std::chrono::steady_clock::now();
	return std::chrono::duration<double, std::nano>(t1 - t0).count() / (m * P);
}

// Bench like check(): base = mcl's {Fp,Fp2}::{add,sub,mul}, f0 = the -arg-p
// variant (prime context as the 4th argument), fs = the rest (llvm baked-p,
// llvm -var-p, x64 asm). Temp vars are initialized as in check(). Prints one
// latency row and one throughput row; the trailing ratios are time / base.
template<class T>
void benchmark(const char *name, int loop, void (*base)(T&, const T&, const T&), FpOp4 f0, std::initializer_list<FpOp> fs)
{
	const size_t n = sizeof(T) / sizeof(Fp);
	cybozu::XorShift rg;
	T x, y;
	for (size_t i = 0; i < n; i++) {
		((Fp*)&x)[i].setByCSPRNG(rg);
		((Fp*)&y)[i].setByCSPRNG(rg);
	}
	const Unit *py = (const Unit*)&y;
	alignas(64) T a[4];
	auto reset = [&]() { for (int k = 0; k < 4; k++) a[k] = x; };
	auto run = [&](int P) {
		std::vector<double> v;
		reset(); v.push_back(measure([&](int k) { base(a[k], a[k], y); }, P, loop));
		reset(); v.push_back(measure([&](int k) { f0((Unit*)&a[k], (const Unit*)&a[k], py, llvm_var_param); }, P, loop));
		for (FpOp f : fs) {
			reset(); v.push_back(measure([&](int k) { f((Unit*)&a[k], (const Unit*)&a[k], py); }, P, loop));
		}
		volatile Unit sink = ((const Unit*)&a[0])[0]; (void)sink;
		return v;
	};
	auto printRow = [&](const char *mode, const std::vector<double>& v) {
		printf("%-5s %-11s", name, mode);
		for (size_t i = 0; i < v.size(); i++) {
			char buf[64];
			if (i == 0) snprintf(buf, sizeof(buf), "%.3f", v[i]); // base
			else snprintf(buf, sizeof(buf), "%.3f(%.2fx)", v[i], v[i] / v[0]);
			printf(" %15s", buf);
		}
		printf("\n");
	};
	printRow("latency", run(1));
	printRow("throughput", run(4));
}

template<class T>
void check_and_bench(const char *name, int loop, void (*base)(T&, const T&, const T&), FpOp4 f0, std::initializer_list<FpOp> fs)
{
	check(name, base, f0, fs);
	benchmark(name, loop, base, f0, fs);
}

int main(int argc, char *argv[]) {
	cybozu::Option opt;
	std::vector<std::string> vs;
	const char *fullSet = "add add2 sub sub2 mul";
	opt.appendVec(&vs, "set", std::string(": select from ") + fullSet);
	opt.appendHelp("h");
	if (!opt.parse(argc, argv)) {
		opt.usage();
		return 1;
	}
	opt.put();
	std::set<std::string> ss(vs.begin(), vs.end());
	const char *pStr = (const char*)llvm_get_prime();
	printf("p=%s\n", pStr);
	Fp::init(pStr, 1, 1);
	bool b;
	Fp2::init(&b);
	if (!b) {
		fprintf(stderr, "Fp2::init error\n");
		return 1;
	}

	printf("unit: ns/op (smaller is faster); base = mcl, (Nx) = time / base\n");
	printf("%-5s %-11s %15s %15s %15s %15s %15s %15s\n",
		"op", "mode", "base", "argp", "llvm", "var", "x64", "x64woadx");
	if (ss.empty() || ss.find("add") != ss.end()) {
		check_and_bench("add", 200000000, Fp::add, llvm_argp_add, {llvm_add, llvm_var_add, x64_add});
	}
	if (ss.empty() || ss.find("add") != ss.end()) {
		check_and_bench("sub", 200000000, Fp::sub, llvm_argp_sub, {llvm_sub, llvm_var_sub, x64_sub});
	}
	if (ss.empty() || ss.find("add2") != ss.end()) {
		check_and_bench("add2", 200000000, Fp2::add, llvm_argp2_add, {llvm2_add, llvm_var2_add, x642_add});
	}
	if (ss.empty() || ss.find("sub2") != ss.end()) {
		check_and_bench("sub2", 200000000, Fp2::sub, llvm_argp2_sub, {llvm2_sub, llvm_var2_sub, x642_sub});
	}
	if (ss.empty() || ss.find("mul") != ss.end()) {
		check_and_bench("mul", 50000000, Fp::mul, llvm_argp_mul, {llvm_mul, llvm_var_mul, x64_mul, x64_mul_wo_adx});
	}
}
